import os
import urllib.request

import cv2
import mediapipe as mp

from mediapipe.tasks import python
from mediapipe.tasks.python import vision


class FaceDetector:
    MODEL_URL = (
        "https://storage.googleapis.com/mediapipe-models/"
        "face_detector/blaze_face_short_range/"
        "float16/1/blaze_face_short_range.tflite"
    )

    MODEL_NAME = "blaze_face_short_range.tflite"

    def __init__(self,
                 minDetectionCon=0.5,
                 modelSelection=0):

        self.minDetectionCon = minDetectionCon

        # modelSelection:
        # 0 -> short range
        # 1 -> full range

        if modelSelection == 0:
            self.MODEL_NAME = "blaze_face_short_range.tflite"
            self.MODEL_URL = (
                "https://storage.googleapis.com/"
                "mediapipe-models/face_detector/"
                "blaze_face_short_range/float16/1/"
                "blaze_face_short_range.tflite"
            )

        else:
            self.MODEL_NAME = "blaze_face_full_range_sparse.tflite"
            self.MODEL_URL = (
                "https://storage.googleapis.com/"
                "mediapipe-models/face_detector/"
                "blaze_face_full_range_sparse/float16/1/"
                "blaze_face_full_range_sparse.tflite"
            )

        self._downloadModel()

        base_options = python.BaseOptions(
            model_asset_path=self.MODEL_NAME
        )

        options = vision.FaceDetectorOptions(
            base_options=base_options,
            min_detection_confidence=minDetectionCon
        )

        self.detector = vision.FaceDetector.create_from_options(
            options
        )

    def _downloadModel(self):

        if not os.path.exists(self.MODEL_NAME):
            print("Downloading MediaPipe Face Model...")
            urllib.request.urlretrieve(
                self.MODEL_URL,
                self.MODEL_NAME
            )
            print("Download Complete.")

    def findFaces(self, img, draw=True):

        imgRGB = cv2.cvtColor(
            img,
            cv2.COLOR_BGR2RGB
        )

        mpImage = mp.Image(
            image_format=mp.ImageFormat.SRGB,
            data=imgRGB
        )

        results = self.detector.detect(mpImage)

        bboxs = []

        for id, detection in enumerate(results.detections):

            box = detection.bounding_box

            x = box.origin_x
            y = box.origin_y
            w = box.width
            h = box.height

            cx = x + w // 2
            cy = y + h // 2

            score = detection.categories[0].score

            bboxInfo = {
                "id": id,
                "bbox": (x, y, w, h),
                "score": [score],
                "center": (cx, cy)
            }

            bboxs.append(bboxInfo)

            if draw:
                cv2.rectangle(
                    img,
                    (x, y),
                    (x + w, y + h),
                    (255, 0, 255),
                    2
                )

                cv2.putText(
                    img,
                    f"{int(score * 100)}%",
                    (x, y - 10),
                    cv2.FONT_HERSHEY_PLAIN,
                    2,
                    (255, 0, 255),
                    2
                )

        return img, bboxs


def main():
    # Initialize the webcam
    # '2' means the third camera connected to the computer, usually 0 refers to the built-in webcam
    cap = cv2.VideoCapture(2)

    # Initialize the FaceDetector object
    # minDetectionCon: Minimum detection confidence threshold
    # modelSelection: 0 for short-range detection (2 meters), 1 for long-range detection (5 meters)
    detector = FaceDetector(minDetectionCon=0.5, modelSelection=0)

    # Run the loop to continually get frames from the webcam
    while True:
        # Read the current frame from the webcam
        # success: Boolean, whether the frame was successfully grabbed
        # img: the captured frame
        success, img = cap.read()

        # Detect faces in the image
        # img: Updated image
        # bboxs: List of bounding boxes around detected faces
        img, bboxs = detector.findFaces(img, draw=True)

        # Check if any face is detected
        if bboxs:
            # Loop through each bounding box
            for bbox in bboxs:
                # bbox contains 'id', 'bbox', 'score', 'center'

                # ---- Get Data  ---- #
                center = bbox["center"]
                x, y, w, h = bbox['bbox']
                score = int(bbox['score'][0] * 100)

        # Display the image in a window named 'Image'
        cv2.imshow("Image", img)
        # Wait for 1 millisecond, and keep the window open
        cv2.waitKey(1)


if __name__ == "__main__":
    main()
